// Extrair dados do payload da Evolution API
const input = $input.first().json;
let body = input.body || input;

if (typeof body === 'string') {
  try {
    body = JSON.parse(body);
  } catch (error) {
    body = {};
  }
}

const data = body.data || {};
const key = data.key || {};
const msg = data.message || {};
const instance = body.instance || data.instance || '';
const modoPessoal = instance === 'fabioos-pessoal';

// Texto da mensagem (suporta conversation ou extendedTextMessage)
const texto = msg.conversation 
  || msg.extendedTextMessage?.text 
  || '';
const textoLimpo = texto.trim();

// Anonimizar n?mero: manter apenas 4 ?ltimos d?gitos
const jid = key.remoteJid || '';
const numeroCompleto = jid.replace('@s.whatsapp.net', '').replace('@g.us', '');
const numeroAnon = '****' + numeroCompleto.slice(-4);

const nome = data.pushName || (modoPessoal ? 'Comando pessoal' : 'Respons?vel');
const timestamp = data.messageTimestamp || Math.floor(Date.now() / 1000);
const dataHora = new Date(timestamp * 1000).toISOString().replace('T', ' ').substring(0, 16);
const hoje = new Date(timestamp * 1000).toISOString().split('T')[0];
const anoMes = hoje.substring(0, 7); // YYYY-MM

// No modo pessoal, aceitar mensagens enviadas pelo pr?prio usu?rio apenas com prefixo FabioOS.
if (key.fromMe && !modoPessoal) {
  return [{ json: { ignorar: true, motivo: 'mensagem_enviada_pelo_numero' } }];
}

if (key.fromMe && modoPessoal && !/^fabioos[,s:]/i.test(textoLimpo)) {
  return [{ json: { ignorar: true, motivo: 'comando_pessoal_sem_prefixo_fabioos' } }];
}

// Ignorar se n?o h? texto
if (!textoLimpo) {
  return [{ json: { ignorar: true, motivo: 'sem_texto' } }];
}

return [{
  json: {
    texto: textoLimpo,
    numeroAnon,
    nome,
    instance,
    modo: modoPessoal ? 'pessoal' : 'pietra',
    dataHora,
    hoje,
    anoMes,
    logFilename: modoPessoal ? `WHATSAPP_PESSOAL_${anoMes}_LOG.md` : `PIETRA_${anoMes}_LOG.md`,
    ignorar: false
  }
}];

// Classificar intent da mensagem com base nas palavras-gatilho do Pietra
const texto = $json.texto.toLowerCase()
  .normalize('NFD').replace(/[\u0300-\u036f]/g, ''); // remove acentos para matching

const categorias = [
  {
    nome: 'ocorrencia',
    nivel: 'alto',
    escalonar: true,
    gatilhos: ['ocorrencia', 'ocorrência', 'suspensao', 'briga', 'conflito', 'bullying', 'agressao', 'ameaca', 'assedio', 'disciplinar', 'expulsao'],
    resposta_key: 'OCORRENCIA_ESCALONAMENTO'
  },
  {
    nome: 'financeiro',
    nivel: 'alto',
    escalonar: false,
    gatilhos: ['mensalidade', 'boleto', 'pagamento', 'atraso', 'debito', 'vencimento', 'inadimplente', 'valor da mensalidade', 'isentao', 'bolsa'],
    resposta_key: 'FINANCEIRO_REDIRECIONAMENTO'
  },
  {
    nome: 'matricula',
    nivel: 'medio',
    escalonar: false,
    gatilhos: ['matricula', 'rematricula', 'renovar matricula', 'prazo de matricula', 'inscricao', 'vaga', 'novo aluno'],
    resposta_key: 'MATRICULA_INFO'
  },
  {
    nome: 'segunda_chamada',
    nivel: 'medio',
    escalonar: false,
    gatilhos: ['segunda chamada', 'faltou na prova', 'nao pode fazer a prova', 'nao fez a prova', 'atestado', 'justificativa de falta', 'falta na avaliacao'],
    resposta_key: 'SEGUNDA_CHAMADA_PROCEDIMENTO'
  },
  {
    nome: 'prova',
    nivel: 'medio',
    escalonar: false,
    gatilhos: ['prova', 'avaliacao', 'simulado', 'recuperacao', 'nota', 'resultado', 'gabarito', 'media', 'conteudo da prova', 'quando e a prova'],
    resposta_key: 'PROVA_DATA_CONTEUDO'
  },
  {
    nome: 'coordenacao',
    nivel: 'medio',
    escalonar: false,
    gatilhos: ['coordenacao', 'coordenador', 'reuniao', 'conversar com a coordenadora', 'agendar', 'reclamacao', 'conselho'],
    resposta_key: 'COORDENACAO_AGENDAMENTO'
  },
  {
    nome: 'secretaria',
    nivel: 'medio',
    escalonar: false,
    gatilhos: ['declaracao', 'historico', 'documento', 'certidao', 'transferencia', 'atestado de matricula', 'ficha do aluno', 'horario de atendimento'],
    resposta_key: 'SECRETARIA_DOCUMENTOS'
  },
  {
    nome: 'duvida_pedagogica',
    nivel: 'medio',
    escalonar: false,
    gatilhos: ['dificuldade', 'reforco', 'nao esta entendendo', 'acompanhamento', 'laudo', 'necessidade especial', 'ajudar em casa', 'atividade extra'],
    resposta_key: 'PEDAGOGICO_REDIRECIONAMENTO'
  },
  {
    nome: 'professor',
    nivel: 'baixo',
    escalonar: false,
    gatilhos: ['professor', 'prof ', 'quero falar com o professor', 'contato do professor'],
    resposta_key: 'PROFESSOR_CONTATO'
  },
  {
    nome: 'material',
    nivel: 'baixo',
    escalonar: false,
    gatilhos: ['lista de material', 'livro', 'apostila', 'caderno', 'uniforme', 'material escolar'],
    resposta_key: 'MATERIAL_LISTA'
  },
  {
    nome: 'horario',
    nivel: 'baixo',
    escalonar: false,
    gatilhos: ['horario', 'que horas comeca', 'que horas termina', 'entrada', 'saida', 'feriado', 'recesso', 'aula amanha'],
    resposta_key: 'HORARIO_INFO'
  }
];

// Contar correspondências por categoria
let melhorCategoria = null;
let melhorPontuacao = 0;

for (const cat of categorias) {
  let pontos = 0;
  for (const gatilho of cat.gatilhos) {
    if (texto.includes(gatilho)) pontos++;
  }
  if (pontos > melhorPontuacao) {
    melhorPontuacao = pontos;
    melhorCategoria = cat;
  }
}

// Se não encontrou nada, classificar como não identificado
if (!melhorCategoria || melhorPontuacao === 0) {
  melhorCategoria = {
    nome: 'nao_classificada',
    nivel: 'medio',
    escalonar: false,
    resposta_key: 'NAO_CLASSIFICADO'
  };
}

// Verificar condições especiais de escalonamento
const palavrasRisco = ['advogado', 'procon', 'processo', 'acao judicial', 'abuso', 'violencia'];
const temRisco = palavrasRisco.some(p => texto.includes(p));
if (temRisco) melhorCategoria.escalonar = true;

return [{
  json: {
    ...($json),
    categoria: melhorCategoria.nome,
    nivel: melhorCategoria.nivel,
    escalonar: melhorCategoria.escalonar || temRisco,
    resposta_key: melhorCategoria.resposta_key,
    pontuacao: melhorPontuacao
  }
}];

// Montar entrada de log anonimizada
const d = $json;
const acao = d.escalonar ? 'escalada' : 'sugestao_preparada';
const logLinha = `| ${d.dataHora} | WhatsApp | ${d.numeroAnon} | ${d.categoria} | ${d.nivel} | ${acao} | pendente |\n`;

// Montar notificação para o professor
const notificacao = [
  `[PIETRA] Nova mensagem recebida`,
  `Canal: WhatsApp | Número: ${d.numeroAnon}`,
  `Categoria: ${d.categoria} | Nível: ${d.nivel}`,
  d.escalonar ? '⚠ ESCALONAMENTO OBRIGATÓRIO — Notificar coordenação' : '',
  ``,
  `Mensagem: "${d.texto}"`,
  ``,
  d.escalonar 
    ? 'Encaminhar imediatamente para a coordenação pedagógica.'
    : `Resposta sugerida (modelo: ${d.resposta_key}):`,
  d.escalonar 
    ? ''
    : 'Ver: 60_Sistemas/Pietra/respostas-modelo/RESPOSTAS_MODELO.md'
].filter(l => l !== undefined).join('\n');

return [{
  json: {
    ...($json),
    logLinha,
    notificacao,
    acao
  }
}];
